Office.onReady(async (info) => {
  if (info.host === Office.HostType.Outlook) {
    document.getElementById("createTask").onclick = createPlannerTask;
    const today = new Date().toISOString().split("T")[0];
document.getElementById("dueDate").value = today;
    await loadUsersFromFlow();
  }
});
async function loadUsersFromFlow() {
  const select = document.getElementById("assigneeEmail");
  const currentUserEmail = Office.context.mailbox.userProfile.emailAddress;

  select.innerHTML = '<option value="">Načítám uživatele...</option>';

  try {
    const config = getConfigFromManifestUrl();
const usersUrl = config.usersFlowUrl;

    const response = await fetch(usersUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: "{}"
    });

    if (!response.ok) {
      throw new Error(`Flow chyba ${response.status}`);
    }

    const users = await response.json();
console.log("USERS FROM FLOW:", users);
showStatus("Načteno z Flow: " + JSON.stringify(users).substring(0, 500), "info");
   select.innerHTML = '<option value="">Přiřadit mně</option>';

users
  .filter(u => u.systemuserid && u.fullname)
  .sort((a, b) =>
    (a.fullname || "").localeCompare(b.fullname || "", "cs")
  )
  .forEach(user => {
    const option = document.createElement("option");

    option.value = user.systemuserid;
    option.textContent = user.jobtitle
      ? `${user.fullname} (${user.jobtitle})`
      : user.fullname;

    select.appendChild(option);
  });
  } catch (error) {
    select.innerHTML = '<option value="">Přiřadit mně</option>';
    showStatus("Nepodařilo se načíst uživatele: " + error.message, "danger");
  }
}
async function createPlannerTask() {
  const status = document.getElementById("status");
  showStatus("Načítám email...", "info");

  const item = Office.context.mailbox.item;

  const subject = item.subject || "";
  const sender = item.from
    ? `${item.from.displayName} <${item.from.emailAddress}>`
    : "";

  const receivedDateTime = item.dateTimeCreated
    ? item.dateTimeCreated.toISOString()
    : "";

  const bodyHtml = await getBodyHtml();
const currentUserEmail = Office.context.mailbox.userProfile.emailAddress;
const selectedAssignee = document.getElementById("assigneeEmail").value;

const assigneeEmail = selectedAssignee || currentUserEmail;
  const payload = {
    subject: subject,
    sender: sender,
    assigneeUserId: selectedAssignee || "",
    receivedDateTime: receivedDateTime,
    bodyHtml: bodyHtml,
    dueDate: document.getElementById("dueDate").value,
    priority: document.getElementById("priority").value,

  };

  status.innerText = "Odesílám do Power Automate...";

const config = getConfigFromManifestUrl();
const flowUrl = config.createFlowUrl;

  try {
    const response = await fetch(flowUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      throw new Error(`HTTP chyba ${response.status}`);
    }

    showStatus("Úkol byl vytvořen.", "success");
  } catch (error) {
    showStatus("Chyba: " + error.message, "danger");
  }
}
function showStatus(message, type = "info") {
  const status = document.getElementById("status");
  status.className = `alert alert-${type} mt-3`;
  status.innerText = message;
}
function getBodyHtml() {
  return new Promise((resolve, reject) => {
    Office.context.mailbox.item.body.getAsync(
      Office.CoercionType.Text,
      (result) => {
        if (result.status === Office.AsyncResultStatus.Succeeded) {
          resolve(result.value);
        } else {
          reject(new Error(result.error.message));
        }
      }
    );
  });
}
function getConfigFromManifestUrl() {
  const params = new URLSearchParams(window.location.search);

  return {
    createFlowUrl: decodeURIComponent(params.get("createFlow") || ""),
    usersFlowUrl: decodeURIComponent(params.get("usersFlow") || "")
  };
}
